module RefModule (clk, clr, d, q);
   input clk, clr;
   input [15:0] d;
   output reg [15:0] q;

     wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
      if (clr)
         q <= 16'b0000000000000000;
      else
         q <= d;
   end
endmodule
